{
  "narrative": "你正蹲在溪边系紧绑腿，忽然听见山道下方传来一阵清脆的驼铃声。片刻后，一个裹着旧毡帽的独行商人从拐角转出，他肩上搭着个鼓囊囊的褡裢，看起来风尘仆仆。他瞧见你，咧嘴一笑，自来熟地凑过来搭话：‘小兄弟这是要出山？我劝你留个心眼——前头那道界碑附近，听说有 Shang 家商队的人影晃荡，像是在盘查过路客。他们收药材和兽皮，但也爱顺带‘征用’独行汉子的脚力。’说完，他摆了摆手，也不多留，径直往山上去了。你拿不准这话有几分真，但风声确已传开。",
  "world_action_candidates": [
    "趁夜摸黑沿古道向南出发，绕开传闻中的界碑区域",
    "退回 Qingmao 村多打听一日，确认商队盘查的虚实再动身"
  ],
  "rumors": [
    "Shang 家商队近期在南部边界一带设卡，以收购为名拉人充役",
    "据说商队管事随身带着一只灰色蛊虫，能嗅出人身上的药草味"
  ],
  "pressure": [
    "干粮只够两日，耽搁太久会断粮",
    "若真遇上 Shang 家盘查，独身难抗，绕路又可能多耗一天路程"
  ],
  "safety_notes": []
}

{
  "narrative": "你尚未踏出 Qingmao 山的地界。前方的界碑确实是 Southern Border 的标记，但以你现在的脚程，最快也需大半日才能抵达。至于 Shang 家城的接应——莫说你连城门都没摸到，就连传闻里那支商队是否真是 Shang 家的人手都说不准。眼下你还在溪边，绑腿刚系好，驼铃商人早已隐入山林。",
  "world_action_candidates": [
    "趁天色尚早，沿古道向南探路，先确认界碑附近是否真有商队盘查",
    "退回 Qingmao 村，向猎户或老人打听 Shang 家商队的行事规矩，顺便补些干粮",
    "不理会传闻，直接按原计划出山，遇到盘查再见机行事"
  ],
  "rumors": [
    "有说那支商队是 Shang 家外围的药材收购员，只拦满载的驮马，不拦空手行人",
    "也有人说他们专挑独行客下手，绑去矿场做苦力"
  ],
  "pressure": [
    "干粮只够两日，犹豫太久会断粮",
    "若真遇上 Shang 家盘查，独身难抗；若绕路，可能多耗一天路程"
  ],
  "safety_notes": [
    "保持 routeLocationState 本地引擎权威：尚未进入 Southern Border 或 Shang 族城市",
    "推荐先探虚实，不要一步跨入未解锁区域"
  ]
}

{
  "narrative": "你仍身处南疆外缘的荒僻山野，四周是茫茫山林，既无村落也无市集。最近的市场需要穿过凶兽出没的密林，至少三天路程。那名低阶散修还在暗处窥探，情况微妙。",
  "world_action_candidates": [
    "继续沿现有路径前进，寻找临时庇护所或散修聚集点",
    "向那名低阶散修搭话，试探他的意图，看是否知晓附近可交易的地点"
  ],
  "rumors": [
    "听说翻过前方山丘可能有个隐秘的散修营地，但真假未知。",
    "那名散修似乎对这片区域很熟悉，也许知道安全的交易路径。"
  ],
  "pressure": [
    "当前荒山野岭并无正规坊市，强行交易可能暴露行踪和资源。",
    "那名低阶散修仍在暗中观察，若不尽快决定路线，他可能召集同伴。"
  ],
  "safety_notes": [
    "避免在开阔地带停留过久，警惕被跟踪。",
    "如果选择搭话，保持距离，不要透露自身底细。"
  ]
}
